func resourceComputeGlobalVmExtensionPolicyDelete(d *schema.ResourceData, meta interface{}) error {
	if d.Get("deletion_policy").(string) == "PREVENT" {
		return fmt.Errorf("cannot destroy ComputeGlobalVmExtensionPolicy without setting deletion_policy=\"DELETE\" and running `terraform apply`")
	}
	if d.Get("deletion_policy").(string) == "ABANDON" {
		log.Printf("[DEBUG] deletion_policy set to \"ABANDON\", removing GlobalVmExtensionPolicy %q from Terraform state without deletion", d.Id())
		return nil
	}
	config := meta.(*transport_tpg.Config)
	userAgent, err := tpgresource.GenerateUserAgentString(d, config.UserAgent)
	if err != nil {
		return err
	}

	billingProject := ""

	project, err := tpgresource.GetProject(d, config)
	if err != nil {
		return fmt.Errorf("Error fetching project for GlobalVmExtensionPolicy: %s", err)
	}
	billingProject = project
	url, err := tpgresource.ReplaceVars(d, config, transport_tpg.BaseUrl(Product, config)+"projects/{{project}}/global/vmExtensionPolicies/{{name}}/delete")
	if err != nil {
		return err
	}

	var obj map[string]interface{}

	// err == nil indicates that the billing_project value was found
	if bp, err := tpgresource.GetBillingProject(d, config); err == nil {
		billingProject = bp
	}

	headers := make(http.Header)
	// predefinedRolloutPlan is required in the request body for GCE VM extension policy deletion.
	obj = map[string]interface{}{
		"predefinedRolloutPlan": "FAST_ROLLOUT",
	}

	log.Printf("[DEBUG] Deleting GlobalVmExtensionPolicy %q", d.Id())
	res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
		Config:    config,
		Method:    "POST",
		Project:   billingProject,
		RawURL:    url,
		UserAgent: userAgent,
		Body:      obj,
		Timeout:   d.Timeout(schema.TimeoutDelete),
		Headers:   headers,
	})
	if err != nil {
		return transport_tpg.HandleNotFoundError(err, d, "GlobalVmExtensionPolicy")
	}

	err = ComputeOperationWaitTime(
		config, res, project, "Deleting GlobalVmExtensionPolicy", userAgent,
		d.Timeout(schema.TimeoutDelete))

	if err != nil {
		return err
	}
	readUrl, err := tpgresource.ReplaceVars(d, config, transport_tpg.BaseUrl(Product, config)+"projects/{{project}}/global/vmExtensionPolicies/{{name}}")
	if err != nil {
		return err
	}

	// Wait for deletion (up to 10 minutes) to avoid eventual consistency issues during subsequent resource deletions (e.g. RolloutPlan)
	deadline := time.Now().Add(10 * time.Minute)
	for {
		_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
			Config:    config,
			Method:    "GET",
			Project:   billingProject,
			RawURL:    readUrl,
			UserAgent: userAgent,
		})
		if err != nil {
			if transport_tpg.IsGoogleApiErrorWithCode(err, 404) {
				break
			}
			return err
		}
		if time.Now().After(deadline) {
			return fmt.Errorf("timeout waiting for GlobalVmExtensionPolicy %q to be deleted", d.Id())
		}
		log.Printf("[DEBUG] GlobalVmExtensionPolicy %q is still deleting, waiting...", d.Id())
		time.Sleep(5 * time.Second)
	}

	// Clean up any historical rollout records owned by this GlobalVmExtensionPolicy
	policyName := ""
	if n, ok := d.GetOk("name"); ok {
		policyName = n.(string)
	}

	if policyName != "" {
		listUrl := transport_tpg.BaseUrl(Product, config) + fmt.Sprintf("projects/%s/global/rollouts?filter=rolloutEntity.orchestratedEntity.orchestrationSource%%20eq%%20%%22.*%s%%22", project, policyName)
		listRes, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
			Config:    config,
			Method:    "GET",
			Project:   billingProject,
			RawURL:    listUrl,
			UserAgent: userAgent,
		})
		if err != nil {
			return fmt.Errorf("Error listing rollouts to clean up references: %s", err)
		}

		if listRes != nil {
			if items, ok := listRes["items"].([]interface{}); ok {
				for _, item := range items {
					if rollout, ok := item.(map[string]interface{}); ok {
						if rolloutName, ok := rollout["name"].(string); ok && rolloutName != "" {
							log.Printf("[DEBUG] Deleting historical rollout %q owned by policy %q to unlock referenced rollout plan", rolloutName, policyName)
							deleteUrl := transport_tpg.BaseUrl(Product, config) + fmt.Sprintf("projects/%s/global/rollouts/%s", project, rolloutName)

							res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
								Config:    config,
								Method:    "DELETE",
								Project:   billingProject,
								RawURL:    deleteUrl,
								UserAgent: userAgent,
							})
							if err != nil {
								log.Printf("[WARNING] Error deleting rollout %q: %s", rolloutName, err)
								continue
							}

							err = ComputeOperationWaitTime(
								config, res, project, fmt.Sprintf("Deleting rollout %q", rolloutName), userAgent,
								d.Timeout(schema.TimeoutDelete))
							if err != nil {
								log.Printf("[WARNING] Error waiting for rollout %q deletion: %s", rolloutName, err)
							}
						}
					}
				}
			}
		}
	}

	log.Printf("[DEBUG] Finished deleting GlobalVmExtensionPolicy %q: %#v", d.Id(), res)
	return nil
}

